mapper.select:
SELECT t.id, t.employee_id, t.destination, t.start_date, t.end_date, t.days, t.reason, t.created_at, t.updated_at, e.employee_no, e.name AS employee_name, d.department_name FROM business_trip_record t INNER JOIN employee e ON t.employee_id = e.id LEFT JOIN department d ON e.department_id = d.id
AND e.status = AND (t.reason IS NULL OR t.reason NOT LIKE CONCAT(, '%'))
AND e.employee_no = #{employeeNo}
AND e.name LIKE CONCAT('%', #{name}, '%')
AND e.department_id = #{departmentId}
AND t.start_date >= #{startDate}
AND t.end_date <= #{endDate}
ORDER BY t.start_date DESC, t.id DESC

SELECT id, employee_id, destination, start_date, end_date, days, reason, created_at, updated_at
FROM business_trip_record
WHERE id = #{id}

mapper.update:
UPDATE business_trip_record
SET reason = CONCAT(, COALESCE(reason, ''))
WHERE id = #{id}
